SELECT 
FROM domain_package_migration_plan


        AND package_id = #{filter.packageId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


        AND status = #{filter.status}


        AND from_version_id = #{filter.fromVersionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


        AND to_version_id = #{filter.toVersionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


        AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


ORDER BY id ASC
LIMIT #{size}

