UPDATE domain_package_migration_plan
SET status = #{newStatus, typeHandler=com.pdp.persistence.typehandler.StringEnumTypeHandler},
    updated_at = #{now, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler},
    revision = revision + 1
WHERE id = #{id, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND revision = #{expectedRevision}

UPDATE domain_package_migration_plan
SET rollback_window_expires_at = #{rollbackWindowExpiresAt, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler},
    updated_at = #{now, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler},
    revision = revision + 1
WHERE id = #{id, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND revision = #{expectedRevision}
